const msg = $json.message;
const chat_id = msg.chat ? msg.chat.id : null;
const from = msg.from || {};
const texto = (msg.text || '').trim();
const nombre = [from.first_name, from.last_name].filter(Boolean).join(' ');
const telegram_user = String(from.id || chat_id || '');
return [{ json: { chat_id, texto, nombre, telegram_user } }];

const d = $('Normalizar Mensaje Tutor').first().json;
const filas = $input.all();
const ses = filas.length ? filas[0].json : { pantalla_actual: '', paso_actual: '', datos_parciales: '{}' };
let datos = {};
try { datos = JSON.parse(ses.datos_parciales || '{}'); } catch (e) { datos = {}; }

const texto = (d.texto || '').trim();
const lower = texto.toLowerCase();
const idTutorSesion = datos.id_tutor || '';
const nombreTutorSesion = datos.nombre_tutor || '';

let ruta;

if (lower === '/salir' || lower === '/cambiartutor') {
  ruta = 'salir';
} else if (!idTutorSesion) {
  if (ses.pantalla_actual === 'esperando_id_tutor') {
    ruta = 'validar_id';
  } else {
    ruta = 'pedir_id';
  }
} else if (ses.pantalla_actual === 'esperando_id_confirmar') {
  ruta = 'confirmar_id';
} else if (ses.pantalla_actual === 'esperando_id_finalizar') {
  ruta = 'finalizar_id';
} else if (ses.pantalla_actual === 'esperando_id_cancelar') {
  ruta = 'cancelar_id';
} else if (lower === '/mistutorias' || texto === '1') {
  ruta = 'ver_tutorias';
} else if (lower === '/confirmar' || texto === '2') {
  ruta = 'pedir_confirmar';
} else if (lower === '/finalizar' || texto === '3') {
  ruta = 'pedir_finalizar';
} else if (lower === '/cancelar' || texto === '4') {
  ruta = 'pedir_cancelar';
} else {
  ruta = 'menu';
}

return [{ json: { ...d, texto, ruta, id_tutor: idTutorSesion, nombre_tutor: nombreTutorSesion } }];

const d = $json;
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user,
  respuesta: '👋 ¡Hola! Para identificarte como tutor, escribe tu ID de tutor (ejemplo: T001).',
  pantalla_actual: 'esperando_id_tutor', paso_actual: 'id', datos_parciales: '{}' } }];

const d = $('Motor de Estados Tutor').first().json;
const filas = $input.all();
if (!filas.length) {
  return [{ json: { ...d, idValido: false, motivo: 'No encontré ningún tutor con ese ID. Verifica que sea correcto (ejemplo: T001) e inténtalo de nuevo.' } }];
}
const t = filas[0].json;
if (t.estado !== 'Activo') {
  return [{ json: { ...d, idValido: false, motivo: 'Ese tutor no está activo en el sistema. Contacta al coordinador académico.' } }];
}
return [{ json: { ...d, idValido: true, id_tutor: t.id_tutor, nombre_tutor: t.nombre } }];

const d = $json;
const texto = `✅ ¡Hola ${d.nombre_tutor}! Quedaste identificado como tutor ${d.id_tutor}.

Elige una opción respondiendo con el número:

1️⃣ Ver mis tutorías
2️⃣ Confirmar una tutoría
3️⃣ Finalizar una tutoría
4️⃣ Cancelar una tutoría

También puedes usar /mistutorias, /confirmar, /finalizar o /cancelar.`;
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user, respuesta: texto,
  pantalla_actual: 'menu', paso_actual: '',
  datos_parciales: JSON.stringify({ id_tutor: d.id_tutor, nombre_tutor: d.nombre_tutor }) } }];

const d = $json;
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user,
  respuesta: `⚠️ ${d.motivo}`, pantalla_actual: 'esperando_id_tutor', paso_actual: 'id', datos_parciales: '{}' } }];

const d = $json;
const texto = `👋 Hola ${d.nombre_tutor}! Elige una opción respondiendo con el número:

1️⃣ Ver mis tutorías
2️⃣ Confirmar una tutoría
3️⃣ Finalizar una tutoría
4️⃣ Cancelar una tutoría

También puedes usar /mistutorias, /confirmar, /finalizar o /cancelar.`;
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user, respuesta: texto,
  pantalla_actual: 'menu', paso_actual: '',
  datos_parciales: JSON.stringify({ id_tutor: d.id_tutor, nombre_tutor: d.nombre_tutor }) } }];

const d = $('Motor de Estados Tutor').first().json;
const filas = $input.all().map(i => i.json);
const activas = filas.filter(f => ['Asignada', 'Confirmada'].includes(f.estado));
let texto;
if (!activas.length) {
  texto = '📭 No tienes tutorías activas asignadas actualmente.';
} else {
  texto = '📚 Tus tutorías:\n\n' + activas.map(t =>
    `• ID ${t.id_tutoria} — ${t.materia}\n  📅 ${t.fecha} 🕐 ${t.hora}\n  Estado: ${t.estado}`
  ).join('\n\n') + '\n\n✅ Escribe /confirmar para CONFIRMAR una tutoría, /finalizar para marcarla como FINALIZADA, o /cancelar para CANCELARLA.\nEn cualquiera de esas opciones, usa el ID que ves arriba (ej. ' + activas[0].id_tutoria + ').';
}
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user, respuesta: texto,
  pantalla_actual: 'menu', paso_actual: '',
  datos_parciales: JSON.stringify({ id_tutor: d.id_tutor, nombre_tutor: d.nombre_tutor }) } }];

const d = $json;
return [{ json: { chat_id: d.chat_id, telegram_user: d.telegram_user,
  respuesta: '✏️ Escribe el ID de la tutoría que quieres CONFIRMAR (usa la opción 1 para ver tus tutorías y sus IDs).',
  pantalla_actual: 'esperando_id_confirmar', paso_actual: 'id',
  datos_parciales: JSON.stringify({ id_tutor: d.id_tutor, nombre_tutor: d.nombre_tutor }) } }];

